Create the Zustand store for voice state management.

## File: `apps/web/lib/stores/voice-store.ts`

Follow existing pattern (e.g., chat-store.ts): Zustand + persist middleware.

```typescript
import { create } from 'zustand';
import { persist } from 'zustand/middleware';

export interface VoiceMessage {
  id: string;                    // crypto.randomUUID()
  role: 'user' | 'assistant';
  text: string;
  audioUrl?: string;             // blob URL for playback (not persisted — recreated)
  timestamp: string;             // ISO 8601
}

export interface VoiceSession {
  id: string;                    // crypto.randomUUID()
  startedAt: string;             // ISO 8601
  title: string;                 // first user message text (first 50 chars)
  messages: VoiceMessage[];
}

interface VoiceStore {
  // --- Transient state (not persisted) ---
  isRecording: boolean;
  isProcessing: boolean;
  isPlaying: boolean;
  error: string | null;
  wsConnected: boolean;
  conversationId: string | null;  // WS conversation ID from server

  // --- Persisted preferences ---
  mode: 'http' | 'websocket';    // default 'http'
  language: 'pl' | 'en';         // default 'pl'
  autoPlayTts: boolean;           // default true
  voiceName: string;              // default 'pl-PL-ZofiaNeural'

  // --- Persisted sessions (max 30) ---
  sessions: VoiceSession[];
  activeSessionId: string | null;

  // --- Transient actions ---
  setRecording: (v: boolean) => void;
  setProcessing: (v: boolean) => void;
  setPlaying: (v: boolean) => void;
  setError: (e: string | null) => void;
  setWsConnected: (v: boolean) => void;
  setConversationId: (id: string | null) => void;

  // --- Preference actions ---
  setMode: (m: 'http' | 'websocket') => void;
  setLanguage: (l: 'pl' | 'en') => void;
  setAutoPlayTts: (v: boolean) => void;
  setVoiceName: (v: string) => void;

  // --- Session actions ---
  createSession: () => string;     // returns new session ID, sets it as active
  addMessage: (sessionId: string, msg: Omit<VoiceMessage, 'id' | 'timestamp'>) => void;
  setActiveSession: (id: string | null) => void;
  deleteSession: (id: string) => void;
  clearSessions: () => void;
}
```

Implementation details:
- `persist` with name `'gilbertus-voice'`
- Use `partialize` to ONLY persist: `mode`, `language`, `autoPlayTts`, `voiceName`, `sessions`, `activeSessionId`. Transient fields reset on page load.
- `createSession`: generate UUID, title='Nowa sesja głosowa', push to sessions[], set activeSessionId. If sessions.length >= 30, remove oldest.
- `addMessage`: find session by id, push new VoiceMessage with `id: crypto.randomUUID()` and `timestamp: new Date().toISOString()`. Auto-update session title from first user message (first 50 chars + '...').
- `deleteSession`: remove from array. If was active, set activeSessionId to null.
- Export both `useVoiceStore` hook and all types.

