## File 1: `apps/web/lib/hooks/use-voice.ts`

The central voice hook. Manages MediaRecorder, Web Audio API, WebSocket, and audio playback.

```typescript
import { useCallback, useRef, useEffect } from 'react';
import { useVoiceStore } from '@/lib/stores/voice-store';
import { voiceAsk, voiceCommand, textToSpeech, getVoiceWsUrl } from '@gilbertus/api-client';
import type { WsServerMessage } from '@gilbertus/api-client';

export function useVoice() {
  const store = useVoiceStore();
  const mediaRecorderRef = useRef<MediaRecorder | null>(null);
  const audioContextRef = useRef<AudioContext | null>(null);
  const analyserRef = useRef<AnalyserNode | null>(null);
  const wsRef = useRef<WebSocket | null>(null);
  const audioRef = useRef<HTMLAudioElement | null>(null);
  const chunksRef = useRef<Blob[]>([]);

  // --- Audio Setup ---
  // On mount: create AudioContext (lazy, on first user interaction)
  // Connect MediaStream → AnalyserNode for waveform visualization

  // --- Recording (HTTP mode) ---
  const startRecording = useCallback(async () => {
    // 1. Request microphone: navigator.mediaDevices.getUserMedia({ audio: true })
    // 2. Create MediaRecorder with mimeType 'audio/webm;codecs=opus' (fallback: 'audio/webm')
    // 3. Connect stream to AudioContext → AnalyserNode for waveform
    // 4. mediaRecorder.ondataavailable = (e) => chunksRef.current.push(e.data)
    // 5. mediaRecorder.start()
    // 6. store.setRecording(true)
  }, [store]);

  const stopRecording = useCallback(async () => {
    // 1. mediaRecorder.stop()
    // 2. store.setRecording(false), store.setProcessing(true)
    // 3. Wait for 'stop' event → create Blob from chunks
    // 4. Ensure/create session if none active
    // 5. Call voiceAsk(blob, store.language, activeSessionId)
    // 6. Add user message (transcript) + assistant message (answer) to store
    // 7. If autoPlayTts && tts_available: call textToSpeech(answer) → playAudio(blob)
    // 8. store.setProcessing(false)
    // 9. On error: store.setError(message), store.setProcessing(false)
  }, [store]);

  // --- Recording (WebSocket mode) ---
  const connectWs = useCallback(() => {
    // 1. const url = getVoiceWsUrl()
    // 2. ws = new WebSocket(url)
    // 3. ws.onopen: send {action:'start', conversation_id: store.conversationId}
    // 4. ws.onmessage: parse JSON or binary
    //    - 'ready': store.setWsConnected(true), store.setConversationId(msg.conversation_id)
    //    - 'transcript': add user message to session
    //    - 'response': add assistant message to session
    //    - binary (ArrayBuffer): create Blob → playAudio
    //    - 'done': store.setProcessing(false)
    //    - 'error': store.setError(msg.message)
    // 5. ws.onclose: store.setWsConnected(false), attempt reconnect with backoff
    // 6. ws.onerror: store.setError('Błąd połączenia WebSocket')
  }, [store]);

  const startRecordingWs = useCallback(async () => {
    // Similar to HTTP but use timeslice=250ms
    // mediaRecorder.ondataavailable sends binary chunks via ws.send(e.data)
  }, [store]);

  const stopRecordingWs = useCallback(() => {
    // mediaRecorder.stop()
    // ws.send('END')
    // store.setRecording(false), store.setProcessing(true)
  }, [store]);

  // --- Audio Playback ---
  const playAudio = useCallback((blob: Blob) => {
    // 1. const url = URL.createObjectURL(blob)
    // 2. audioRef.current = new Audio(url)
    // 3. audio.onplay → store.setPlaying(true)
    // 4. audio.onended → store.setPlaying(false), URL.revokeObjectURL(url)
    // 5. audio.play()
  }, [store]);

  const stopPlayback = useCallback(() => {
    // audioRef.current?.pause(), store.setPlaying(false)
  }, [store]);

  // --- Voice Command ---
  const executeCommand = useCallback(async (commandText: string) => {
    // 1. store.setProcessing(true)
    // 2. Call textToSpeech to get command audio, or use voiceCommand endpoint
    // 3. Display response
    // For quick commands from chips: POST /voice/tts with command text, then parse
    // Alternative: use the /voice/command with a pre-recorded blob — but for chip commands,
    //   better to directly call the relevant API (brief, status, etc.)
    // For MVP: add the command as user message, call voiceAsk with text-only (if supported)
    //   or just show the command type in the UI
  }, [store]);

  // --- Keyboard shortcut ---
  useEffect(() => {
    const handleKeyDown = (e: KeyboardEvent) => {
      if (e.code === 'Space' && !e.repeat && !isInputFocused()) {
        e.preventDefault();
        if (store.mode === 'http') startRecording();
        else startRecordingWs();
      }
    };
    const handleKeyUp = (e: KeyboardEvent) => {
      if (e.code === 'Space' && !isInputFocused()) {
        e.preventDefault();
        if (store.mode === 'http') stopRecording();
        else stopRecordingWs();
      }
    };
    // isInputFocused: check document.activeElement tagName (INPUT, TEXTAREA, [contenteditable])
    window.addEventListener('keydown', handleKeyDown);
    window.addEventListener('keyup', handleKeyUp);
    return () => { window.removeEventListener('keydown', handleKeyDown); window.removeEventListener('keyup', handleKeyUp); };
  }, [store.mode, startRecording, stopRecording, startRecordingWs, stopRecordingWs]);

  // --- WS lifecycle ---
  useEffect(() => {
    if (store.mode === 'websocket') connectWs();
    return () => { wsRef.current?.close(); };
  }, [store.mode, connectWs]);

  // --- Cleanup ---
  useEffect(() => {
    return () => {
      audioContextRef.current?.close();
      mediaRecorderRef.current?.stream?.getTracks().forEach(t => t.stop());
    };
  }, []);

  return {
    ...store,
    analyserNode: analyserRef.current,
    startRecording: store.mode === 'http' ? startRecording : startRecordingWs,
    stopRecording: store.mode === 'http' ? stopRecording : stopRecordingWs,
    playAudio,
    stopPlayback,
    executeCommand,
  };
}

function isInputFocused(): boolean {
  const el = document.activeElement;
  if (!el) return false;
  const tag = el.tagName;
  return tag === 'INPUT' || tag === 'TEXTAREA' || (el as HTMLElement).isContentEditable;
}
```

## File 2: `apps/web/lib/hooks/use-voice-health.ts`

Simple React Query hook for health polling.

```typescript
import { useQuery } from '@tanstack/react-query';
import { getVoiceHealth } from '@gilbertus/api-client';

export function useVoiceHealth() {
  return useQuery({
    queryKey: ['voice-health'],
    queryFn: ({ signal }) => getVoiceHealth(signal),
    refetchInterval: 30_000,   // poll every 30s
    staleTime: 25_000,
    retry: 1,
  });
}
```

